<?php
namespace Database\Seeders;
use Illuminate\Database\Seeder;use Spatie\Permission\Models\{Permission,Role};use Spatie\Permission\PermissionRegistrar;
class SecurityGovernanceRoleSeeder extends Seeder {public function run():void{$new=['admin.security.incident_recurrence.view','admin.security.incident_recurrence.manage','admin.security.corrective_actions.verify','admin.security.postmortem_review_cycles.view','admin.security.postmortem_review_cycles.manage','admin.security.postmortem_review_cycles.complete'];$existing=Role::findOrCreate('owner','web')->permissions->pluck('name')->all();$all=array_unique(array_merge($existing,$new));foreach($new as $p)Permission::findOrCreate($p,'web');foreach(['owner','admin','security_manager'] as $r)Role::findOrCreate($r,'web')->givePermissionTo($new);app(PermissionRegistrar::class)->forgetCachedPermissions();}}
